# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public static PlayerStats Instance;
    
    public float health = 100f;
    public float maxHealth = 100f;
    public int currency = 0;
    public int level = 1;
    public float attackDamage = 10f;
    public float defense = 5f;
    
    void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }
    
    public void TakeDamage(float damage)
    {
        float actualDamage = CalculateDamage(damage);
        health -= actualDamage;
        
        if (health <= 0)
        {
            health = 0;
            Die();
        }
    }
    
    public float CalculateDamage(float incomingDamage)
    {
        float damageReduction = defense / (defense + 100);
        float actualDamage = incomingDamage * (1 - damageReduction);
        return Mathf.Max(1f, actualDamage);
    }
    
    public void Heal(float amount)
    {
        health += amount;
        if (health > maxHealth)
        {
            health = maxHealth;
        }
    }
    
    public void AddCurrency(int amount)
    {
        currency += amount;
    }
    
    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            return true;
        }
        return false;
    }
    
    void Die()
    {
        Debug.Log("Player Died!");
    }
}

public class ShopItem
{
    public string itemName;
    public int basePrice;
    public string itemType;
    public float value;
    
    public ShopItem(string name, int price, string type, float val)
    {
        itemName = name;
        basePrice = price;
        itemType = type;
        value = val;
    }
    
    public int GetPrice()
    {
        return basePrice;
    }
}

public class ShopManager : MonoBehaviour
{
    public static ShopManager Instance;
    public List<ShopItem> shopItems = new List<ShopItem>();
    
    void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
        }
        else
        {
            Destroy(gameObject);
        }
        
        InitializeShop();
    }
    
    void InitializeShop()
    {
        shopItems.Add(new ShopItem("Health Potion", 50, "consumable", 30f));
        shopItems.Add(new ShopItem("Sword Upgrade", 200, "weapon", 5f));
        shopItems.Add(new ShopItem("Shield Upgrade", 150, "armor", 3f));
        shopItems.Add(new ShopItem("Max Health Boost", 300, "permanent", 20f));
        shopItems.Add(new ShopItem("Currency Pack Small", 100, "currency", 500f));
        shopItems.Add(new ShopItem("Currency Pack Large", 500, "currency", 3000f));
    }
    
    public bool PurchaseItem(string itemName)
    {
        ShopItem item = shopItems.Find(x => x.itemName == itemName);
        
        if (item == null)
        {
            Debug.Log("Item not found!");
            return false;
        }
        
        int price = item.GetPrice();
        
        if (PlayerStats.Instance.SpendCurrency(price))
        {
            ApplyItemEffect(item);
            Debug.Log("Purchased: " + itemName);
            return true;
        }
        else
        {
            Debug.Log("Not enough currency!");
            return false;
        }
    }
    
    void ApplyItemEffect(ShopItem item)
    {
        switch (item.itemType)
        {
            case "consumable":
                PlayerStats.Instance.Heal(item.value);
                break;
            case "weapon":
                PlayerStats.Instance.attackDamage += item.value;
                break;
            case "armor":
                PlayerStats.Instance.defense += item.value;
                break;
            case "permanent":
                PlayerStats.Instance.maxHealth += item.value;
                PlayerStats.Instance.health += item.value;
                break;
            case "currency":
                PlayerStats.Instance.AddCurrency((int)item.value);
                break;
        }
    }
}

public class Enemy : MonoBehaviour
{
    public float health = 50f;
    public float attackDamage = 15f;
    public int currencyReward = 25;
    
    public void TakeDamage(float damage)
    {
        health -= damage;
        
        if (health <= 0)
        {
            Die();
        }
    }
    
    public void Attack()
    {
        if (PlayerStats.Instance != null)
        {
            PlayerStats.Instance.TakeDamage(attackDamage);
        }
    }
    
    void Die()
    {
        PlayerStats.Instance.AddCurrency(currencyReward);
        Destroy(gameObject);
    }
}

public class CombatSystem : MonoBehaviour
{
    public void PlayerAttack(Enemy enemy)
    {
        if (enemy != null && PlayerStats.Instance != null)
        {
            float damage = PlayerStats.Instance.attackDamage;
            enemy.TakeDamage(damage);
        }
    }
}

public class IAPManager : MonoBehaviour
{
    public static IAPManager Instance;
    
    void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
