    public void PurchaseCurrencyPack(int amount)
    {
        PlayerStats.Instance.AddCurrency(amount);
        Debug.Log("Added " + amount + " currency from IAP");
    }
    
    public void PurchaseHealthPack()
    {
        PlayerStats.Instance.Heal(PlayerStats.Instance.maxHealth);
        Debug.Log("Player fully healed from IAP");
    }
    
    public void PurchasePremiumUpgrade()
    {
        PlayerStats.Instance.attackDamage *= 1.5f;
        PlayerStats.Instance.defense *= 1.5f;
        PlayerStats.Instance.maxHealth *= 1.5f;
        PlayerStats.Instance.health = PlayerStats.Instance.maxHealth;
        Debug.Log("Premium upgrade applied");
    }
}

